            },
            new Shipment
            {
                TrackingNumber = "SHP-20250102-E5F6G7H8",
                Origin = "Chicago, IL",
                Destination = "Miami, FL",
                Status = ShipmentStatus.Pending,
                EstimatedDelivery = DateTime.UtcNow.AddDays(5),
                CustomerEmail = "customer2@example.com",
                Description = "Furniture delivery",
                CreatedAt = DateTime.UtcNow.AddDays(-1),
                UpdatedAt = DateTime.UtcNow
            },
            new Shipment
            {
                TrackingNumber = "SHP-20250103-I9J0K1L2",
                Origin = "Seattle, WA",
                Destination = "Denver, CO",
                Status = ShipmentStatus.Delivered,
                EstimatedDelivery = DateTime.UtcNow.AddDays(-1),
                ActualDelivery = DateTime.UtcNow.AddDays(-1),
                CustomerEmail = "customer3@example.com",
                Description = "Books and media",
                CreatedAt = DateTime.UtcNow.AddDays(-5),
                UpdatedAt = DateTime.UtcNow.AddDays(-1)
            },
            new Shipment
            {
