@page "/"

<PageTitle>ShipmentTracker - Home</PageTitle>

<div class="container mt-4">
    <div class="text-center mb-5">
        <h1 class="display-4">📦 ShipmentTracker</h1>
        <p class="lead">Track your shipments in real-time. Enter your tracking number below to get started.</p>
    </div>

    <div class="row justify-content-center">
        <div class="col-md-8 col-lg-6">
            <div class="card shadow">
                <div class="card-body p-4">
                    <h5 class="card-title mb-3">Track a Shipment</h5>
                    <div class="input-group">
                        <input type="text" class="form-control" placeholder="Enter tracking number (e.g., SHP-20250101-A1B2C3D4)"
                               @bind="trackingNumber" @bind:event="oninput" @onkeydown="HandleKeyDown" />
                        <button class="btn btn-primary" @onclick="Search">
                            Search
                        </button>
                    </div>
                    @if (!string.IsNullOrEmpty(errorMessage))
                    {
                        <div class="alert alert-warning mt-3">@errorMessage</div>
                    }
                </div>
            </div>
        </div>
    </div>

    <div class="row mt-5 text-center">
        <div class="col-md-4">
            <h4>🚚 Real-time Tracking</h4>
            <p>Monitor your shipments from origin to destination with live status updates.</p>
        </div>
        <div class="col-md-4">
            <h4>📋 Dispatch Management</h4>
            <p>Create and manage shipments with our dispatcher dashboard.</p>
