    private string searchNumber = string.Empty;
    private ShipmentDto? shipment;
    private bool isLoading;
    private string? errorMessage;

    protected override async Task OnParametersSetAsync()
    {
        if (!string.IsNullOrEmpty(TrackingNumber))
        {
            searchNumber = TrackingNumber;
            await DoSearch();
        }
    }

    private async Task Search()
    {
        await DoSearch();
    }

    private async Task DoSearch()
    {
        if (string.IsNullOrWhiteSpace(searchNumber))
        {
            errorMessage = "Please enter a tracking number.";
            return;
        }

        try
        {
            isLoading = true;
            errorMessage = null;
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchNumber.Trim());
            if (shipment == null)
                errorMessage = $"No shipment found with tracking number '{searchNumber.Trim()}'.";
