    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private CreateShipmentModel model = new();
    private bool isSubmitting;
    private string? successMessage;
    private string? errorMessage;

    private async Task HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(model.Origin) || string.IsNullOrWhiteSpace(model.Destination))
        {
            errorMessage = "Origin and Destination are required.";
            return;
        }

        try
        {
            isSubmitting = true;
            errorMessage = null;
            successMessage = null;

            var dto = new CreateShipmentDto
            {
                Origin = model.Origin,
                Destination = model.Destination,
                CustomerEmail = model.CustomerEmail ?? string.Empty,
                Description = model.Description ?? string.Empty,
                EstimatedDelivery = model.EstimatedDelivery
            };

            var result = await ShipmentService.CreateShipmentAsync(dto);
            successMessage = $"Shipment created successfully! Tracking #: {result.TrackingNumber}";
            model = new CreateShipmentModel();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create shipment: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private class CreateShipmentModel
    {
        public string Origin { get; set; } = string.Empty;
        public string Destination { get; set; } = string.Empty;
        public string? CustomerEmail { get; set; }
        public string? Description { get; set; }
        public DateTime? EstimatedDelivery { get; set; }
    }
}

