@code {
    [Parameter] public string? TrackingNumber { get; set; }
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private string searchNumber = string.Empty;
    private ShipmentDto? shipment;
    private bool isLoading;
    private string? errorMessage;

    protected override async Task OnParametersSetAsync()
    {
        if (!string.IsNullOrEmpty(TrackingNumber))
        {
            searchNumber = TrackingNumber;
            await DoSearch();
        }
    }

    private async Task Search()
    {
        await DoSearch();
    }

    private async Task DoSearch()
    {
        if (string.IsNullOrWhiteSpace(searchNumber))
        {
            errorMessage = "Please enter a tracking number.";
            return;
        }

        try
        {
            isLoading = true;
            errorMessage = null;
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchNumber.Trim());
            if (shipment == null)
                errorMessage = $"No shipment found with tracking number '{searchNumber.Trim()}'.";
        }
        catch (Exception ex)
        {
            errorMessage = $"Error searching: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            _ = Search();
    }

    private static int GetProgressPercentage(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.InTransit => 40,
        ShipmentStatus.OutForDelivery => 70,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 30,
        _ => 0
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger progress-bar-striped progress-bar-animated",
        _ => "bg-secondary"
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

