+    private IEnumerable<ShipmentDto> FilteredShipments => shipments.Where(s =>
+    {
+        var matchesSearch = string.IsNullOrEmpty(searchQuery) ||
+            s.TrackingNumber.Contains(searchQuery, StringComparison.OrdinalIgnoreCase) ||
+            s.Destination.Contains(searchQuery, StringComparison.OrdinalIgnoreCase);
+
+        var matchesStatus = string.IsNullOrEmpty(statusFilter) ||
+            s.Status.ToString() == statusFilter;
+
+        return matchesSearch && matchesStatus;
+    });
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadShipments();
+    }
+
+    private async Task LoadShipments()
+    {
+        try
+        {
+            isLoading = true;
+            shipments = await ShipmentService.GetAllShipmentsAsync();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to load shipments: {ex.Message}";
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private async Task UpdateStatus(int id, ShipmentStatus newStatus)
+    {
+        try
+        {
+            await ShipmentService.UpdateShipmentStatusAsync(id, newStatus);
+            await LoadShipments();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to update status: {ex.Message}";
+        }
+    }
